<?php declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';$pdo=obtenerConexion();$qtxt=trim((string)($_GET['q']??''));$estado=(string)($_GET['estado']??'');$sql='SELECT p.*,u.nombre,u.apellido,u.correo FROM pedidos p JOIN usuarios u ON u.id=p.usuario_id WHERE 1';$pa=[];if($qtxt!==''){$sql.=' AND (p.numero LIKE :q OR u.correo LIKE :q OR p.stripe_checkout_session_id LIKE :q)';$pa['q']='%'.$qtxt.'%';}if(in_array($estado,['pendiente','esperando_pago','pagado','fallido','cancelado','reembolsado'],true)){$sql.=' AND p.estado=:e';$pa['e']=$estado;}$sql.=' ORDER BY p.created_at DESC';$q=$pdo->prepare($sql);$q->execute($pa);$pedidos=$q->fetchAll();cmsCabecera('Pedidos','pedidos/index.php','Consulta pagos e historial; Stripe es la única fuente de confirmación automática.');?><div class="card card-rounded"><div class="card-body"><form class="row g-2 mb-4"><div class="col-md-6"><input class="form-control" name="q" value="<?=atenea_e($qtxt)?>" placeholder="Pedido, correo o identificador Stripe"></div><div class="col-md-4"><select class="form-select" name="estado"><option value="">Todos los estados</option><?php foreach(['pendiente','esperando_pago','pagado','fallido','cancelado','reembolsado']as$e):?><option <?=$estado===$e?'selected':''?>><?=$e?></option><?php endforeach;?></select></div><div class="col-md-2"><button class="btn btn-outline-primary w-100">Filtrar</button></div></form><div class="table-responsive"><table class="table table-hover"><thead><tr><th>Pedido</th><th>Cliente</th><th>Fecha</th><th>Total</th><th>Estado</th><th>Stripe</th><th>Detalle</th></tr></thead><tbody><?php foreach($pedidos as$p):?><tr><td><?=atenea_e($p['numero'])?></td><td><?=atenea_e(trim($p['nombre'].' '.$p['apellido']))?><small class="d-block"><?=atenea_e($p['correo'])?></small></td><td><?=date('d/m/Y H:i',strtotime($p['created_at']))?></td><td>$<?=number_format((float)$p['total'],2)?> <?=strtoupper($p['moneda'])?></td><td><span class="badge badge-opacity-<?=$p['estado']==='pagado'?'success':($p['estado']==='fallido'?'danger':'warning')?>"><?=atenea_e($p['estado'])?></span></td><td><small><?=atenea_e((string)($p['stripe_payment_intent_id']?:$p['stripe_checkout_session_id']))?></small></td><td><a class="btn btn-sm btn-outline-primary" href="detalle.php?id=<?=$p['id']?>">Ver</a></td></tr><?php endforeach;?><?php if(!$pedidos):?><tr><td colspan="7" class="text-center py-5">No hay pedidos.</td></tr><?php endif;?></tbody></table></div></div></div><?php cmsPie();?>
